import { useEffect, useState } from 'react';
import API from '../api/axios';

function AdminPage() {
  const [members, setMembers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [searchMember, setSearchMember] = useState('');
  const [searchPost, setSearchPost] = useState('');
  const [confirmDelete, setConfirmDelete] = useState(null);
  const [activeView, setActiveView] = useState('all');

  const loadAdminData = async () => {
    setError('');
    setLoading(true);

    try {
      const [usersRes, postsRes, messagesRes] = await Promise.all([
        API.get('/admin/users'),
        API.get('/admin/posts'),
        API.get('/admin/messages'),
      ]);

      setMembers(usersRes.data);
      setPosts(postsRes.data);
      setMessages(messagesRes.data);
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to load admin dashboard data.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadAdminData();
  }, []);

  const handleToggleStatus = async (memberId) => {
    try {
      const res = await API.put(`/admin/users/${memberId}/status`);
      setMembers((prev) => prev.map((member) => (member._id === memberId ? res.data.user : member)));
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to update member status.');
    }
  };

  const handleRemovePost = async (postId) => {
    try {
      await API.put(`/admin/posts/${postId}/remove`);
      setPosts((prev) => prev.map((post) => (post._id === postId ? { ...post, status: 'removed' } : post)));
    } catch (err) {
      setError(err?.response?.data?.message || 'Unable to remove post.');
    }
  };

  return (
    <main className="admin-page">
      <section className="admin-header">
        <h2>Admin Dashboard</h2>
        <p>Review all members, posts, and incoming contact messages from one place.</p>
      </section>

      {/* Statistics Cards */}
      <section className="admin-stats">
        <div className="stat-card">
          <div className="stat-icon">👥</div>
          <div className="stat-content">
            <h4>Total Members</h4>
            <p className="stat-number">{members.length}</p>
            <span className="stat-label">Active: {members.filter(m => m.status === 'active').length}</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">📝</div>
          <div className="stat-content">
            <h4>Total Posts</h4>
            <p className="stat-number">{posts.length}</p>
            <span className="stat-label">Published: {posts.filter(p => p.status !== 'removed').length}</span>
          </div>
        </div>
        <div className="stat-card">
          <div className="stat-icon">💬</div>
          <div className="stat-content">
            <h4>Messages</h4>
            <p className="stat-number">{messages.length}</p>
            <span className="stat-label">Unreviewed</span>
          </div>
        </div>
      </section>

      {loading ? (
        <p className="loading-text">⏳ Loading admin data...</p>
      ) : error ? (
        <p className="error-text">❌ {error}</p>
      ) : (
        <>
          {/* Members Section */}
          <section className="admin-section">
            <div className="section-header">
              <h3>👥 Members</h3>
              <input
                type="text"
                placeholder="Search by name or email..."
                value={searchMember}
                onChange={(e) => setSearchMember(e.target.value)}
                className="search-input"
              />
            </div>
            {members.length === 0 ? (
              <div className="empty-state">
                <p>📭 No members found.</p>
              </div>
            ) : (
              <div className="table-wrapper">
                <table className="admin-table">
                  <thead>
                    <tr>
                      <th>Name</th>
                      <th>Email</th>
                      <th>Status</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {members
                      .filter(
                        (member) =>
                          member.name.toLowerCase().includes(searchMember.toLowerCase()) ||
                          member.email.toLowerCase().includes(searchMember.toLowerCase())
                      )
                      .map((member) => (
                        <tr key={member._id}>
                          <td className="member-name">{member.name}</td>
                          <td className="member-email">{member.email}</td>
                          <td>
                            <span className={`status-badge status-${member.status}`}>
                              {member.status === 'active' ? '✓ Active' : '✕ Inactive'}
                            </span>
                          </td>
                          <td>
                            <button
                              className={`action-btn ${member.status === 'active' ? 'btn-danger' : 'btn-success'}`}
                              onClick={() => handleToggleStatus(member._id)}
                            >
                              {member.status === 'active' ? '🔒 Deactivate' : '🔓 Activate'}
                            </button>
                          </td>
                        </tr>
                      ))}
                  </tbody>
                </table>
              </div>
            )}
          </section>

          {/* Posts Section */}
          <section className="admin-section">
            <div className="section-header">
              <h3>📝 Posts</h3>
              <input
                type="text"
                placeholder="Search by title or author..."
                value={searchPost}
                onChange={(e) => setSearchPost(e.target.value)}
                className="search-input"
              />
            </div>
            {posts.length === 0 ? (
              <div className="empty-state">
                <p>📭 No posts found.</p>
              </div>
            ) : (
              <div className="table-wrapper">
                <table className="admin-table">
                  <thead>
                    <tr>
                      <th>Title</th>
                      <th>Author</th>
                      <th>Status</th>
                      <th>Date</th>
                      <th>Action</th>
                    </tr>
                  </thead>
                  <tbody>
                    {posts
                      .filter(
                        (post) =>
                          post.title.toLowerCase().includes(searchPost.toLowerCase()) ||
                          (post.author?.name || '').toLowerCase().includes(searchPost.toLowerCase())
                      )
                      .map((post) => (
                        <tr key={post._id} className={post.status === 'removed' ? 'removed-row' : ''}>
                          <td className="post-title">{post.title}</td>
                          <td>{post.author?.name || 'Unknown'}</td>
                          <td>
                            <span className={`status-badge status-${post.status || 'published'}`}>
                              {post.status === 'removed' ? '🚫 Removed' : '✓ Published'}
                            </span>
                          </td>
                          <td className="date-cell">{new Date(post.createdAt).toLocaleDateString()}</td>
                          <td>
                            <button
                              className={`action-btn ${post.status === 'removed' ? 'btn-disabled' : 'btn-danger'}`}
                              onClick={() => setConfirmDelete(post._id)}
                              disabled={post.status === 'removed'}
                            >
                              {post.status === 'removed' ? '✓ Removed' : '🗑 Remove'}
                            </button>
                          </td>
                        </tr>
                      ))}
                  </tbody>
                </table>
              </div>
            )}
          </section>

          {/* Contact Messages Section */}
          <section className="admin-section">
            <h3>💬 Contact Messages</h3>
            {messages.length === 0 ? (
              <div className="empty-state">
                <p>📭 No contact messages yet.</p>
              </div>
            ) : (
              <div className="table-wrapper">
                <table className="admin-table">
                  <thead>
                    <tr>
                      <th>Name</th>
                      <th>Email</th>
                      <th>Message</th>
                      <th>Received</th>
                    </tr>
                  </thead>
                  <tbody>
                    {messages.map((message) => (
                      <tr key={message._id}>
                        <td className="message-name">{message.name}</td>
                        <td>{message.email}</td>
                        <td className="message-text">{message.message}</td>
                        <td className="date-cell">{new Date(message.createdAt).toLocaleDateString()}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </section>

          {/* Confirmation Dialog */}
          {confirmDelete && (
            <div className="modal-overlay">
              <div className="confirmation-modal">
                <h3>⚠️ Confirm Action</h3>
                <p>Are you sure you want to remove this post? This action cannot be undone.</p>
                <div className="modal-actions">
                  <button className="btn-cancel" onClick={() => setConfirmDelete(null)}>
                    Cancel
                  </button>
                  <button
                    className="btn-confirm"
                    onClick={() => {
                      handleRemovePost(confirmDelete);
                      setConfirmDelete(null);
                    }}
                  >
                    Yes, Remove
                  </button>
                </div>
              </div>
            </div>
          )}
        </>
      )}
    </main>
  );
}

export default AdminPage;
